import { writeFile } from "node:fs/promises";
import { buildGeneratedKnowledgeFixtures } from "./eval-fixtures.mjs";
import { seedProjects } from "../src/seed.ts";

const outputPath = new URL("../seed.sql", import.meta.url);
const generated = buildGeneratedKnowledgeFixtures().map((item) => item.knowledge);
const projects = mergeKnowledge([...generated, ...seedProjects]);
const insertBatchSize = 25;

const sql = [
  "-- Generated by scripts/generate-seed-sql.mjs. Do not edit by hand.",
  "-- Seeds local D1 with hand-authored seed knowledge plus generated eval fixtures.",
  "",
  insertProjects(projects),
  "",
  insertMetrics(projects),
  "",
  insertAgentCards(projects),
  ""
].join("\n");

await writeFile(outputPath, sql);

console.log(JSON.stringify({ output: "seed.sql", projects: projects.length, generatedFixtures: generated.length }, null, 2));

function mergeKnowledge(items) {
  const byId = new Map();
  for (const item of items) {
    byId.set(item.project.id.toLowerCase(), item);
  }
  return Array.from(byId.values()).sort((a, b) => a.project.id.localeCompare(b.project.id));
}

function insertProjects(items) {
  return insertBatches(
    [
      "INSERT OR REPLACE INTO projects (",
      "  id, owner, name, full_name, github_url, homepage_url, description, language,",
      "  topics_json, license, stars, forks, open_issues, default_branch,",
      "  created_at, updated_at, pushed_at, synced_at",
      ") VALUES"
    ],
    items.map(({ project }) =>
      tuple([
        project.id,
        project.owner,
        project.name,
        project.fullName,
        project.githubUrl,
        project.homepageUrl,
        project.description,
        project.language,
        JSON.stringify(project.topics),
        project.license,
        project.stars,
        project.forks,
        project.openIssues,
        project.defaultBranch,
        project.createdAt,
        project.updatedAt,
        project.pushedAt,
        project.syncedAt
      ])
    )
  );
}

function insertMetrics(items) {
  return insertBatches(
    [
      "INSERT OR REPLACE INTO project_metrics (",
      "  project_id, stars_30d_delta, commits_30d, releases_180d, contributors_90d,",
      "  issue_first_response_median_hours, recent_push_days, git_score,",
      "  maintenance_score, signal_confidence_json, calculated_at",
      ") VALUES"
    ],
    items.map(({ metrics }) =>
      tuple([
        metrics.projectId,
        metrics.stars30dDelta,
        metrics.commits30d,
        metrics.releases180d,
        metrics.contributors90d,
        metrics.issueFirstResponseMedianHours,
        metrics.recentPushDays,
        metrics.gitScore,
        metrics.maintenanceScore,
        JSON.stringify(metrics.signalConfidence ?? {}),
        metrics.calculatedAt
      ])
    )
  );
}

function insertAgentCards(items) {
  return insertBatches(
    [
      "INSERT OR REPLACE INTO agent_cards (",
      "  project_id, project_kind, collection_json, category, difficulty, deployment_json, cloudflare_ready,",
      "  use_cases_json, not_good_for_json, alternatives_json, summary_for_agent,",
      "  classification_json, schema_version, generated_at",
      ") VALUES"
    ],
    items.map(({ agentCard }) =>
      tuple([
        agentCard.projectId,
        agentCard.projectKind ?? "project",
        JSON.stringify(agentCard.collectionMetadata ?? {}),
        agentCard.category,
        agentCard.difficulty,
        JSON.stringify(agentCard.deployment),
        agentCard.cloudflareReady ? 1 : 0,
        JSON.stringify(agentCard.useCases),
        JSON.stringify(agentCard.notGoodFor),
        JSON.stringify(agentCard.alternatives),
        agentCard.summaryForAgent,
        JSON.stringify(agentCard.classification ?? {}),
        agentCard.schemaVersion,
        agentCard.generatedAt
      ])
    )
  );
}

function tuple(values) {
  return `(${values.map(sqlValue).join(", ")})`;
}

function insertBatches(header, tuples) {
  const statements = [];
  for (let index = 0; index < tuples.length; index += insertBatchSize) {
    statements.push([...header, tuples.slice(index, index + insertBatchSize).join(",\n"), ";"].join("\n"));
  }
  return statements.join("\n\n");
}

function sqlValue(value) {
  if (value === null || value === undefined) {
    return "NULL";
  }
  if (typeof value === "number") {
    return Number.isFinite(value) ? String(value) : "NULL";
  }
  return `'${String(value).replaceAll("'", "''")}'`;
}
